// pubspec.yaml:
//   dependencies:
//     hive: ^2.2.3
//     hive_flutter: ^1.1.0
//   dev_dependencies:
//     hive_generator: ^2.0.1
//     build_runner: ^2.4.13

// main.dart
void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  await Hive.initFlutter();                    // one-time setup
  await Hive.openBox('settings');              // open a box (creates on first use)
  runApp(const MyApp());
}

// Simple KV
final box = Hive.box('settings');
await box.put('theme', 'dark');
final theme = box.get('theme', defaultValue: 'light');   // 'dark'
await box.delete('theme');
final has = box.containsKey('theme');

// Multiple boxes for organization
final settings = Hive.box('settings');
final cache    = Hive.box('response_cache');
final progress = Hive.box('progress');

// Iterate
for (final key in box.keys) {
  print('$key = ${box.get(key)}');
}

// Watch — reactive stream of changes
box.watch(key: 'theme').listen((event) {
  print('theme changed to ${event.value}');
});

// ============ Storing custom classes with TypeAdapter ============
// user.dart
import 'package:hive/hive.dart';
part 'user.g.dart';

@HiveType(typeId: 0)
class User {
  User({required this.id, required this.name, required this.email});

  @HiveField(0) final int id;
  @HiveField(1) final String name;
  @HiveField(2) final String email;
}

// Run: dart run build_runner build --delete-conflicting-outputs
// Generates User TypeAdapter.

// Register + use
void main() async {
  await Hive.initFlutter();
  Hive.registerAdapter(UserAdapter());

  final users = await Hive.openBox<User>('users');
  await users.put('u1', User(id: 1, name: 'Ada', email: 'ada@x.com'));

  final ada = users.get('u1');   // typed User instance
  print(ada?.name);
}

// ============ Encrypted box ============
import 'package:hive/hive.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

Future<Box> openSecureBox() async {
  // Key stored in platform Secure Storage (Keychain / Keystore) — NOT in the app.
  final storage = const FlutterSecureStorage();
  var keyStr = await storage.read(key: 'hive_key');
  if (keyStr == null) {
    final key = Hive.generateSecureKey();       // random 32 bytes
    keyStr = base64Url.encode(key);
    await storage.write(key: 'hive_key', value: keyStr);
  }
  final key = base64Url.decode(keyStr);
  return await Hive.openBox('sensitive', encryptionCipher: HiveAesCipher(key));
}

